# Used to test custom op
import torch.nn as nn

def func_op_a(input):
    return input + 1

def func_op_b(input):
    return input + 2

class NNModOpA(nn.Module):
    def forward(self, input):
        return input * 3

class NNModOpB(nn.Module):
    def forward(self, input):
        return input * 4
